import sailpoint.object.ProvisioningPlan;
import sailpoint.object.ProvisioningProject;
import sailpoint.object.Identity;
import org.apache.log4j.Logger;
import org.apache.log4j.Level;
import sailpoint.object.Filter;
import sailpoint.object.QueryOptions;
import sailpoint.api.Provisioner;
import org.apache.commons.logging.LogFactory;

Logger alog = Logger.getLogger("workflow.AffiliateInbound-User-Workflow");
if (AffiliateJson != null) {
  Map map = generateMapFromJson(AffiliateJson);
  String operation = "Update";
  String identityName = map.get("identityName").toString();
  String type = map.get("type").toString();
  Identity identity = null;
  QueryOptions options = new QueryOptions();
  options.addFilter(Filter.and(Filter.like("name", identityName),Filter.eq("type",type)));
  int countObjects = context.countObjects(Identity.class, options);
  if (countObjects < 1) {
    identity = new Identity();
    identity.setName(identityName);
    flow = "IdentityCreateRequest";
    operation = "Create"; 
  }
  else {
    identity = context.getObjectByName(Identity.class, identityName);
  }
  plan = buildPlan(map, operation, identity);     
  wfcontext.setVariable("flow", flow);
  wfcontext.setVariable("plan", plan);
  wfcontext.setVariable("identityName", identityName);
  wfcontext.setVariable("identityDisplayName", identityName);
  Provisioner provisioner = new Provisioner(context);
  provisioner.setNoLocking(true);
  provisioner.setOptimisticProvisioning(true);
  ProvisioningProject project=provisioner.compile(plan);
  if(project!=null) {
    provisioner.execute(project);
  }
}


import sailpoint.object.Workflow;
import sailpoint.object.Identity;
import sailpoint.object.Attributes;
import sailpoint.workflow.StandardWorkflowHandler;
import sailpoint.request.WorkflowRequestExecutor;
import sailpoint.object.Request;
import sailpoint.object.RequestDefinition;
import sailpoint.api.RequestManager;
import java.util.Calendar;

if (identityName != null)
{
  String workflowName = "Affiliate Refresh";
  String requestName = workflowName + "' for: " + identityName;
  String requesterId = "spadmin";

  Workflow eventWorkflow = context.getObject(Workflow.class, workflowName);
  Identity id = context.getObjectByName(Identity.class, requesterId);

  Attributes reqArgs = new Attributes();
  reqArgs.put(StandardWorkflowHandler.ARG_REQUEST_DEFINITION, WorkflowRequestExecutor.DEFINITION_NAME);
  reqArgs.put(StandardWorkflowHandler.ARG_WORKFLOW, workflowName);
  reqArgs.put(StandardWorkflowHandler.ARG_REQUEST_NAME, requestName);

  Attributes wfArgs = new Attributes();
  wfArgs.put("identityName", identityName);
  wfArgs.put("workflow", eventWorkflow.getName());
  reqArgs.putAll(wfArgs);

  Calendar calendar = Calendar.getInstance();
  calendar.add(Calendar.MINUTE, 1);

  Request req = new Request();
  RequestDefinition reqdef = context.getObject(RequestDefinition.class, "Workflow Request");
  req.setDefinition(reqdef);
  req.setOwner(id);
  req.setName(requestName);
  req.setEventDate(calendar.getTime());
  req.setAttributes( reqdef, reqArgs );
  RequestManager.addRequest(context, req);
}
